import { useMap } from '@vis.gl/react-maplibre';
import { isString } from 'lodash-es';
import { createElement, type ReactNode, useLayoutEffect } from 'react';
import { createRoot } from 'react-dom/client';

import { useSafeSvgParser } from './use-safe-svg-parser.js';
import { DEFAULT_INPUT_ICON_SIZE } from '../constants.js';
import type { MapShape } from '../types/shapes.js';
import { attachImageToMap } from '../utils/attach-image-to-map.js';
import { createBitmapConfigOptions } from '../utils/create-bitmap-config-options.js';
import { getDataUri } from '../utils/get-data-uri.js';
import { getScaledSymbolSize } from '../utils/get-scaled-symbol-size.js';

export const useAttachImageFromIcon = (
  icon: string | MapShape | ReactNode,
  suffix: string,
  outputSize?: number,
) => {
  const { elementAsString, ref } = useSafeSvgParser();
  const defaultScaledIconSize = getScaledSymbolSize();

  // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
  const { current: map } = useMap()!;
  const img = new Image(defaultScaledIconSize, defaultScaledIconSize);

  /*
   * As we can only create a reference in a React Node, but we need a virtual
   * 'root' element in the DOM to attach it, we create a 'div'
   * container that lately will hold the React Node. This is done to ensure
   * everything is cached prior any manipulation.
   */
  // Create a div element that acts as a container node in the DOM
  const fakeDomContainer = document.createElement('div');
  useLayoutEffect(() => {
    if (isString(icon)) {
      return;
    }
    // Create a React Node that will have a ref callback to be run when loaded and
    // the input icon as a children
    const reactNodeRefContainer = createElement('div', { ref }, icon);
    // Attach React Node with the ref callback into DOM Node
    const root = createRoot(fakeDomContainer);
    root.render(reactNodeRefContainer);
  }, [icon]);

  // Remove cached element to free resources
  fakeDomContainer.remove();

  const stringUrl = getDataUri(elementAsString);

  img.addEventListener('load', () => {
    createImageBitmap(
      img,
      0,
      0,
      DEFAULT_INPUT_ICON_SIZE,
      DEFAULT_INPUT_ICON_SIZE,
      createBitmapConfigOptions(outputSize),
    ).then((bitmap) => {
      if (!map) {
        return;
      }
      const iconName = `custom-icon-${suffix}`;
      attachImageToMap(map, bitmap, iconName);
    });
  });
  img.src = stringUrl;

  return !isString(icon);
};
